def select_action(obs: np.ndarray) -> int:
    ball_x = obs[49]
    ball_y = obs[54]
    paddle_y = obs[51]
    ball_center = ball_y
    paddle_center = paddle_y + 10
    dist_to_paddle = 160 - ball_x
    if dist_to_paddle < 30:
        dead_zone = 4
    elif dist_to_paddle < 80:
        dead_zone = 8
    else:
        dead_zone = 12
    if ball_center < paddle_center - dead_zone:
        return 2
    elif ball_center > paddle_center + dead_zone:
        return 3
    return 0
